<script>
import VChart from 'vue-echarts';
import { use } from 'echarts/core';
import { CanvasRenderer } from 'echarts/renderers';
import { BarChart, RadarChart } from 'echarts/charts';
import {
  TitleComponent,
  TooltipComponent,
  LegendComponent,
  GridComponent,
  RadarComponent
} from 'echarts/components';
import { rentData, commuteData, survivalEconomics, realCases, insights } from '@/data/realData';

use([
  CanvasRenderer,
  BarChart,
  RadarChart,
  TitleComponent,
  TooltipComponent,
  LegendComponent,
  GridComponent,
  RadarComponent
]);

export default {
  name: 'RealityGapPage',
  components: {
    VChart
  },
  data() {
    return {
      rentData,
      commuteData,
      savingsData: survivalEconomics.annualSavings,
      realCases,
      insights: insights.keyFindings
    }
  },
  computed: {
    // 租金收入比图表
    incomeRatioOption() {
      const data6k = survivalEconomics.incomeVsRent.filter(d => d.income === 6000);
      const data8k = survivalEconomics.incomeVsRent.filter(d => d.income === 8000);
      const data10k = survivalEconomics.incomeVsRent.filter(d => d.income === 10000);
      
      return {
        tooltip: {
          trigger: 'axis',
          axisPointer: { type: 'shadow' },
          formatter: (params) => {
            let result = params[0].name + '<br/>';
            params.forEach(item => {
              result += `${item.seriesName}: ${item.value}%<br/>`;
            });
            return result;
          }
        },
        legend: {
          data: ['月入6000元', '月入8000元', '月入10000元'],
          top: 10
        },
        grid: {
          left: '3%',
          right: '4%',
          bottom: '3%',
          top: '15%',
          containLabel: true
        },
        xAxis: {
          type: 'category',
          data: data6k.map(d => d.station)
        },
        yAxis: {
          type: 'value',
          name: '租金占收入比(%)',
          axisLabel: {
            formatter: '{value}%'
          }
        },
        series: [
          {
            name: '月入6000元',
            type: 'bar',
            data: data6k.map(d => d.ratio),
            itemStyle: { color: '#F56C6C' }
          },
          {
            name: '月入8000元',
            type: 'bar',
            data: data8k.map(d => d.ratio),
            itemStyle: { color: '#E6A23C' }
          },
          {
            name: '月入10000元',
            type: 'bar',
            data: data10k.map(d => d.ratio),
            itemStyle: { color: '#67C23A' }
          }
        ]
      };
    },
    
    // 生活质量雷达图
    qualityRadarOption() {
      const qualityData = survivalEconomics.qualityOfLife;
      const stations = Object.keys(qualityData);
      
      return {
        tooltip: {
          trigger: 'item'
        },
        legend: {
          data: stations.map(key => qualityData[key].station),
          bottom: 10
        },
        radar: {
          indicator: [
            { name: '租金负担\n(分数越低越好)', max: 10 },
            { name: '通勤便利\n(分数越高越好)', max: 10 },
            { name: '储蓄能力\n(分数越高越好)', max: 10 }
          ],
          radius: '60%'
        },
        series: [{
          type: 'radar',
          data: stations.map(key => ({
            name: qualityData[key].station,
            value: [
              10 - qualityData[key].rentBurden, // 反转租金负担
              qualityData[key].commuteTime,
              qualityData[key].savingAbility
            ]
          }))
        }]
      };
    }
  },
  methods: {
    goNext() {
      this.$parent.nextPage();
    }
  }
}
</script>

